// ─── Utility Components ─────────────────────────────────────────
function Badge({ children, color = COLORS.accent, bg }) {
  return (
    <span style={{
      fontSize: 10, fontWeight: 600, fontFamily: FONTS.mono, letterSpacing: 1,
      textTransform: "uppercase", color, background: bg || `${color}18`,
      padding: "3px 8px", borderRadius: 4, whiteSpace: "nowrap",
    }}>{children}</span>
  );
}

function Stat({ label, value, sub, color = COLORS.text, small }) {
  return (
    <div style={{ textAlign: "center" }}>
      <div style={{ fontSize: small ? 22 : 28, fontWeight: 700, fontFamily: FONTS.mono, color, lineHeight: 1.1 }}>{value}</div>
      <div style={{ fontSize: 11, color: COLORS.textMuted, marginTop: 4, fontFamily: FONTS.body, fontWeight: 500 }}>{label}</div>
      {sub && <div style={{ fontSize: 10, color: COLORS.textDim, marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

function Card({ children, style, glow }) {
  return (
    <div style={{
      background: COLORS.card, border: `1px solid ${COLORS.cardBorder}`,
      borderRadius: 12, padding: 20, position: "relative", overflow: "hidden",
      ...(glow ? { boxShadow: `0 0 40px ${COLORS.accentGlow}` } : {}),
      ...style,
    }}>{children}</div>
  );
}

function Input({ label, value, onChange, type = "number", step, min, max, prefix, suffix, style: sx }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 4, ...sx }}>
      {label && <label style={{ fontSize: 10, fontWeight: 600, fontFamily: FONTS.mono, color: COLORS.textMuted, letterSpacing: 0.8, textTransform: "uppercase" }}>{label}</label>}
      <div style={{ display: "flex", alignItems: "center", background: COLORS.surface, border: `1px solid ${COLORS.cardBorder}`, borderRadius: 6, padding: "6px 10px", gap: 4 }}>
        {prefix && <span style={{ fontSize: 13, color: COLORS.textDim, fontFamily: FONTS.mono }}>{prefix}</span>}
        <input type={type} value={value} onChange={e => onChange(type === "number" ? parseFloat(e.target.value) || 0 : e.target.value)}
          step={step} min={min} max={max}
          style={{ flex: 1, background: "transparent", border: "none", outline: "none", color: COLORS.text, fontSize: 14, fontFamily: FONTS.mono, width: "100%", minWidth: 0 }} />
        {suffix && <span style={{ fontSize: 11, color: COLORS.textDim, fontFamily: FONTS.mono }}>{suffix}</span>}
      </div>
    </div>
  );
}

function TextInput({ label, value, onChange, placeholder, style: sx }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 4, ...sx }}>
      {label && <label style={{ fontSize: 10, fontWeight: 600, fontFamily: FONTS.mono, color: COLORS.textMuted, letterSpacing: 0.8, textTransform: "uppercase" }}>{label}</label>}
      <input type="text" value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
        style={{ background: COLORS.surface, border: `1px solid ${COLORS.cardBorder}`, borderRadius: 6, padding: "8px 10px", color: COLORS.text, fontSize: 13, fontFamily: FONTS.body, outline: "none", width: "100%", boxSizing: "border-box" }} />
    </div>
  );
}

function Btn({ children, onClick, active, color = COLORS.accent, small, disabled, style: sx }) {
  return (
    <button onClick={onClick} disabled={disabled} style={{
      background: active ? `${color}22` : "transparent",
      border: `1px solid ${active ? color : COLORS.cardBorder}`,
      borderRadius: 8, padding: small ? "5px 12px" : "8px 18px",
      color: active ? color : COLORS.textMuted, fontSize: small ? 11 : 12,
      fontWeight: 600, fontFamily: FONTS.mono, cursor: disabled ? "not-allowed" : "pointer",
      letterSpacing: 0.5, textTransform: "uppercase", transition: "all 0.2s",
      opacity: disabled ? 0.4 : 1, ...sx,
    }}>{children}</button>
  );
}

// ─── Audit Trail Tooltip — hover to reveal formula math ─────────
function AuditTip({ children, formula, label }) {
  const [show, setShow] = useState(false);
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const ref = useRef(null);
  const handleEnter = (e) => {
    const rect = ref.current?.getBoundingClientRect();
    if (rect) setPos({ x: rect.left, y: rect.bottom + 4 });
    setShow(true);
  };
  return (
    <span ref={ref} onMouseEnter={handleEnter} onMouseLeave={() => setShow(false)} style={{ position: "relative", cursor: "help", borderBottom: "1px dotted rgba(99,102,241,0.35)" }}>
      {children}
      {show && formula && (
        <span style={{
          position: "fixed", left: Math.min(pos.x, (typeof window !== "undefined" ? window.innerWidth - 360 : 200)),
          top: pos.y, zIndex: 9999, width: "auto", maxWidth: 350, minWidth: 180,
          background: "#1a1a2e", color: "#e0e0e0", border: "1px solid #6366F144",
          borderRadius: 8, padding: "8px 12px", fontSize: 10, fontFamily: "'JetBrains Mono',monospace",
          lineHeight: 1.6, boxShadow: "0 8px 24px rgba(0,0,0,0.35)", pointerEvents: "none",
        }}>
          {label && <span style={{ display: "block", fontSize: 8, color: "#A855F7", textTransform: "uppercase", letterSpacing: 1.5, marginBottom: 3, fontWeight: 700 }}>{label}</span>}
          <span style={{ color: "#93C5FD", whiteSpace: "pre-wrap", wordBreak: "break-word" }}>{formula}</span>
        </span>
      )}
    </span>
  );
}

