        const removeFormula = (id) => setCustomFormulas(prev => prev.filter(f => f.id !== id));
        const toggleFormula = (id) => setCustomFormulas(prev => prev.map(f => f.id === id ? { ...f, enabled: !f.enabled } : f));
        const activeCustom = customFormulas.filter(f => f.enabled);

